// frontend/src/pages/Dashboard.js
import React, { useState, useEffect } from 'react';
import axios from 'axios';

const Dashboard = () => {
  const [userName, setUserName] = useState('');
  const [applications, setApplications] = useState([]);
  const [loading, setLoading] = useState(true);
  
  // AI States
  const [aiRecommendations, setAiRecommendations] = useState([]);
  const [aiLoading, setAiLoading] = useState(false);
  const [resumeCategory, setResumeCategory] = useState(null);
  const [resumeExists, setResumeExists] = useState(false);
  const AI_API_URL = 'http://localhost:5001';

  const token = localStorage.getItem('token');

  // Load user data and applications
  useEffect(() => {
    loadUserData();
    loadApplications();
    loadAIRecommendations();
  }, []);

  const loadUserData = async () => {
    try {
      const response = await axios.get('http://localhost:5000/api/auth/user', {
        headers: { 'x-auth-token': token }
      });
      setUserName(response.data.name);
    } catch (error) {
      console.error('Error loading user:', error);
    }
  };

  const loadApplications = async () => {
    try {
      const response = await axios.get('http://localhost:5000/api/applications', {
        headers: { 'x-auth-token': token }
      });
      setApplications(response.data || []);
    } catch (error) {
      console.error('Error loading applications:', error);
    }
    setLoading(false);
  };

  // AI Recommendation Function - Loads from backend and localStorage
  const loadAIRecommendations = async () => {
    setAiLoading(true);
    try {
      let resumeText = '';
      
      // Try to get resume from backend first (find Resume Upload entry)
      try {
        const response = await axios.get('http://localhost:5000/api/applications', {
          headers: { 'x-auth-token': token }
        });
        
        if (response.data && response.data.length > 0) {
          // Look for the resume upload entry
          const resumeEntry = response.data.find(app => app.jobTitle === 'Resume Upload');
          if (resumeEntry && resumeEntry.resumeText) {
            resumeText = resumeEntry.resumeText;
            console.log('Resume found in database');
          }
          // If not found, try the first application's resume text
          if (!resumeText && response.data[0].resumeText) {
            resumeText = response.data[0].resumeText;
            console.log('Resume found in first application');
          }
        }
      } catch (err) {
        console.log('Backend fetch failed:', err.message);
      }
      
      // If no resume in backend, try localStorage
      if (!resumeText) {
        resumeText = localStorage.getItem('userResume') || '';
        if (resumeText) {
          console.log('Resume loaded from localStorage');
        }
      }
      
      if (resumeText) {
        setResumeExists(true);
        console.log('Resume found, analyzing...');
        
        // Get category prediction
        try {
          const categoryRes = await axios.post(`${AI_API_URL}/predict/category`, {
            resume_text: resumeText
          });
          setResumeCategory(categoryRes.data.predicted_category);
        } catch (err) {
          console.error('Category prediction failed:', err);
        }
        
        // Get job recommendations
        const sampleJobs = [
          { title: 'Software Engineer', description: 'Python, Django, React, SQL, AWS, JavaScript' },
          { title: 'Data Scientist', description: 'Python, Machine Learning, SQL, Pandas, NumPy, Statistics' },
          { title: 'Full Stack Developer', description: 'React, Node.js, MongoDB, JavaScript, HTML, CSS' },
          { title: 'DevOps Engineer', description: 'AWS, Docker, Kubernetes, Jenkins, CI/CD, Linux' },
          { title: 'Backend Developer', description: 'Python, Django, Flask, PostgreSQL, REST APIs' },
          { title: 'Frontend Developer', description: 'React, JavaScript, HTML, CSS, Redux' },
          { title: 'Project Manager', description: 'Agile, Scrum, Leadership, Communication, JIRA' },
          { title: 'HR Generalist', description: 'Recruitment, Employee Relations, HR policies, Onboarding' }
        ];
        
        const matches = [];
        for (const job of sampleJobs) {
          try {
            const matchRes = await axios.post(`${AI_API_URL}/predict/match`, {
              resume_text: resumeText,
              job_description: job.description,
              job_title: job.title
            });
            matches.push({
              title: job.title,
              score: matchRes.data.match_score,
              level: matchRes.data.match_level,
              matching_skills: matchRes.data.matching_skills || 0,
              total_skills: matchRes.data.total_job_skills || 0
            });
          } catch (err) {
            console.error(`Error matching ${job.title}:`, err);
          }
        }
        setAiRecommendations(matches.sort((a, b) => b.score - a.score));
      } else {
        setResumeExists(false);
        console.log('No resume found');
      }
    } catch (error) {
      console.error('AI loading error:', error);
    }
    setAiLoading(false);
  };

  const getMatchColor = (score) => {
    if (score >= 70) return '#28a745';
    if (score >= 50) return '#17a2b8';
    if (score >= 30) return '#ffc107';
    return '#dc3545';
  };

  const getMatchLevel = (score) => {
    if (score >= 70) return 'Excellent';
    if (score >= 50) return 'Good';
    if (score >= 30) return 'Fair';
    return 'Poor';
  };

  return (
    <div style={{ padding: '20px', maxWidth: '1200px', margin: '0 auto' }}>
      <h1>📊 Dashboard</h1>
      <p>Welcome back, <strong>{userName || 'User'}!</strong></p>

      {/* AI Recommendations Section */}
      <div style={{
        background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
        color: 'white',
        padding: '20px',
        borderRadius: '10px',
        marginBottom: '30px'
      }}>
        <h2 style={{ color: 'white', marginTop: 0 }}>🤖 AI Job Recommendations</h2>
        
        {aiLoading ? (
          <p>🤖 Analyzing your resume...</p>
        ) : resumeCategory ? (
          <>
            <p>Based on your resume, you're a match for <strong>{resumeCategory}</strong> roles</p>
            <div style={{ display: 'grid', gap: '10px', marginTop: '15px' }}>
              {aiRecommendations.slice(0, 5).map((job, idx) => (
                <div key={idx} style={{
                  background: 'rgba(255,255,255,0.2)',
                  borderRadius: '8px',
                  padding: '12px',
                  display: 'flex',
                  justifyContent: 'space-between',
                  alignItems: 'center',
                  flexWrap: 'wrap'
                }}>
                  <div>
                    <strong>{job.title}</strong>
                    {job.matching_skills > 0 && (
                      <div style={{ fontSize: '12px', opacity: 0.8 }}>
                        🎯 {job.matching_skills}/{job.total_skills} skills match
                      </div>
                    )}
                  </div>
                  <div style={{ textAlign: 'right' }}>
                    <span style={{
                      fontSize: '20px',
                      fontWeight: 'bold',
                      color: getMatchColor(job.score)
                    }}>
                      {job.score}%
                    </span>
                    <div style={{ fontSize: '12px' }}>{getMatchLevel(job.score)} Match</div>
                  </div>
                </div>
              ))}
            </div>
            <button 
              onClick={loadAIRecommendations}
              style={{
                marginTop: '15px',
                padding: '8px 16px',
                background: 'white',
                color: '#667eea',
                border: 'none',
                borderRadius: '5px',
                cursor: 'pointer'
              }}
            >
              🔄 Refresh Recommendations
            </button>
          </>
        ) : (
          <div>
            <p>📄 Upload a resume to get AI-powered job recommendations</p>
            <button 
              onClick={() => window.location.href = '/upload-resume'}
              style={{
                marginTop: '10px',
                padding: '8px 16px',
                background: 'white',
                color: '#667eea',
                border: 'none',
                borderRadius: '5px',
                cursor: 'pointer'
              }}
            >
              📤 Go to Upload Resume
            </button>
          </div>
        )}
      </div>

      {/* Your Applications Section */}
      <h2>📝 Your Applications</h2>
      {loading ? (
        <p>Loading...</p>
      ) : applications.length === 0 ? (
        <div style={{ textAlign: 'center', padding: '40px', background: '#f8f9fa', borderRadius: '10px' }}>
          <p>No applications yet. Start by adding one!</p>
          <button 
            onClick={() => window.location.href = '/applications'}
            style={{
              marginTop: '10px',
              padding: '8px 16px',
              background: '#007bff',
              color: 'white',
              border: 'none',
              borderRadius: '5px',
              cursor: 'pointer'
            }}
          >
            ➕ Add Application
          </button>
        </div>
      ) : (
        <div style={{ display: 'grid', gap: '15px' }}>
          {applications.slice(0, 5).map((app, idx) => (
            <div key={idx} style={{
              border: '1px solid #ddd',
              borderRadius: '8px',
              padding: '15px',
              background: 'white',
              display: 'flex',
              justifyContent: 'space-between',
              alignItems: 'center',
              flexWrap: 'wrap'
            }}>
              <div>
                <h3 style={{ margin: '0 0 5px 0' }}>{app.jobTitle || 'Application'}</h3>
                <p style={{ color: '#666', margin: 0 }}>
                  <strong>{app.companyName || 'Company'}</strong> • {app.status || 'Applied'}
                </p>
              </div>
              <div style={{ fontSize: '12px', color: '#999' }}>
                {new Date(app.createdAt).toLocaleDateString()}
              </div>
            </div>
          ))}
          {applications.length > 5 && (
            <button 
              onClick={() => window.location.href = '/applications'}
              style={{
                padding: '8px 16px',
                background: 'transparent',
                color: '#007bff',
                border: '1px solid #007bff',
                borderRadius: '5px',
                cursor: 'pointer'
              }}
            >
              View All {applications.length} Applications →
            </button>
          )}
        </div>
      )}
    </div>
  );
};

export default Dashboard;
